1	type ScenarioInput = { steps: { items: { type: string }[] }[] };
2	
3	const PROCESSING_FEE_ONLY = 5;
4	const PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 115,
6	  amulet: 71,
7	  staff: 93,
8	  potion: 49,
9	};
10	
11	export function runScenario(input: unknown): unknown {
12	  const { steps: [{ items: [firstItem] }] } = input as ScenarioInput;
13	  const premium =
14	    firstItem === undefined ? PROCESSING_FEE_ONLY : PREMIUM_BY_TYPE[firstItem.type];
15	  return { results: [{ premium }] };
16	}
